-- Enrichment marathon batch: Tailscale, Tailwind, Talend, Talkyard, Tally, Tallyfy, Taplio, Taskade

-- ── Tailscale ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tailscale is a zero-configuration mesh VPN built on WireGuard that lets teams securely connect devices, servers, and services across any network without managing firewall rules or VPN concentrators.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $8/user/month)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Toronto, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tailscale Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Tailscale costs, how its WireGuard-based mesh VPN works, and whether it fits your team. Plans, features, pros and cons compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tailscale is a mesh VPN and zero-trust networking platform built on the open-source WireGuard protocol. Founded in 2019 by former Google engineers Avery Pennarun, David Crawshaw, David Carney, and Brad Fitzpatrick, the company is legally headquartered in Toronto, Canada, and operates as a remote-first organization with roughly 300 employees worldwide. Tailscale creates a private, encrypted mesh network (a tailnet) directly between a user's devices and servers, removing the need for traditional VPN concentrators, port forwarding, or complex firewall rules. It uses NAT traversal and end-to-end encryption so devices can reach each other as if on the same LAN, regardless of physical location. The product is aimed at developers, IT and DevOps teams, and businesses that need secure remote access to internal services, homelabs, Kubernetes clusters, and cloud infrastructure. Tailscale offers a free Personal plan for up to 6 users, a Standard plan at $8 per user per month with SCIM and MDM support, and a Premium plan at $18 per user per month adding just-in-time access and network flow logs, plus a custom-priced Enterprise tier. The company has raised over $275 million in venture funding, including a 2025 Series C led by Accel.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c69ab424-480e-464f-8a10-266de3ca5887';

