-- ── Talend ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Talend is an enterprise data integration and ETL platform for connecting, transforming, and governing data across cloud, hybrid, and on-premises environments, now part of Qlik.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Redwood City, California, United States (originally founded in Suresnes, France)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Talend Review: Data Integration Platform Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Talend is an enterprise ETL and data integration platform now owned by Qlik. Learn about its features, pricing model, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Talend is an enterprise data integration, data quality, and data governance platform founded in 2005 by Bertrand Diard and Fabrice Bonan. It pioneered commercial open-source data integration software, launching Talend Open Studio in 2006 as a free, open-source ETL tool that competed with proprietary enterprise platforms from vendors like Informatica and IBM. The company grew into a full commercial data fabric provider, was publicly listed on Nasdaq, and was acquired by analytics company Qlik, with the acquisition completing on May 16, 2023. Talend was historically dual-headquartered in Suresnes, France, and Redwood City, California. Talend Data Fabric, its flagship commercial product, unifies data integration, integrity, and governance capabilities so enterprises can extract, transform, cleanse, and load data across cloud, hybrid, and multi-cloud environments. It is used primarily by data engineering, IT, and analytics teams at mid-size to large enterprises that need to consolidate data from many source systems into data warehouses, lakes, or applications. Pricing for Talend's commercial products is not publicly listed and requires contacting sales for a custom quote based on usage and modules; the legacy Talend Open Studio components were distributed under an open-source license. As of 2026, Talend operates as part of Qlik's broader data and analytics portfolio.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '503e1e80-efff-4b6e-b3f4-9321fcb8e174';

