-- ── Talkyard ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Talkyard is an open-source community discussion platform that combines forums, Q&A, idea voting, chat, and embeddable blog comments in one tool.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); hosted plans from EUR 4/month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Stockholm, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Talkyard Review: Open-Source Forum Software Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Talkyard is an open-source forum, Q&A, and blog comments platform. See its features, self-hosted vs hosted pricing, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Talkyard is an open-source community discussion platform developed by Kaj Magnus Lindberg through the Swedish company Debiki, headquartered in Stockholm, Sweden. It merges features from Stack Overflow, Discourse, Reddit, Slack, and Disqus into a single tool that supports threaded discussion forums, question-and-answer sites, idea voting boards, chat channels, and embeddable blog comment widgets. The software is released under an open-source license (AGPL) and can be self-hosted for free on a customer's own server, or run as a paid hosted service managed by the Talkyard team. Talkyard is aimed at companies, open-source projects, and online communities that want a knowledge-base-style forum with anti-groupthink features like hidden votes and optional anonymous commenting, rather than a simple flat comment thread. Hosted pricing is billed per active coworker (a monthly active participant) starting at EUR 4 per month on the Standard plan, rising to EUR 12 per month per active coworker on the Business plan (minimum EUR 300 per month), with a custom-priced Enterprise tier for larger organizations needing professional services. A free trial of the hosted version is available with no credit card required. Talkyard positions itself as a privacy-conscious, self-hostable alternative to closed, ad-supported comment and community platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1345ae06-82b8-4acb-9958-4dfcce5198b6';

