-- ── Tally ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tally (tally.so) is a free, no-code online form builder known for its clean design and a generous free tier with unlimited forms and submissions.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Ghent, Belgium$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tally Review 2026: Free Form Builder Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Tally (tally.so) is a free no-code form builder with unlimited forms and submissions. Compare pricing, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tally, found at tally.so, is a no-code online form builder founded in 2020 by Marie Martens and Filip Minev in Ghent, Belgium, where the company remains headquartered. It is not related to the Indian accounting software also called Tally or TallyPrime. Tally is bootstrapped and self-funded, with a product philosophy centered on a document-like, Notion-style editing experience that lets users build forms by typing content and inserting blocks, rather than dragging elements onto a canvas. Its standout feature is a free plan that includes unlimited forms and unlimited submissions, collection of payments, signatures, and file uploads, conditional logic, and support for over 45 languages, which is unusually generous compared to most competing form builders that cap free-tier submissions. Tally targets startups, indie developers, marketers, and small businesses that need surveys, lead-capture forms, waitlists, or feedback forms without a steep learning curve or cost. Paid plans remove Tally branding and add custom domains, unlimited team collaboration, advanced customization with custom CSS, and premium integrations like Google Analytics and Meta Pixel: the Pro plan is EUR 20 per month and the Business plan is EUR 65 per month, both billed monthly or yearly with two months free on annual billing. Integrations include Google Sheets, Notion, Airtable, Zapier, Make, and webhooks.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '65992870-15b8-4319-a2e6-b0c8037a92bf';

