-- ── Tallyfy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tallyfy is a workflow and business process management platform that turns manual checklists and standard operating procedures into trackable, automated workflows.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$10/month per Light seat$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$St. Louis, Missouri, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tallyfy Review: Workflow Automation Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Tallyfy turns SOPs and checklists into trackable workflows. See pricing plans, key features, pros, cons, and frequently asked questions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tallyfy is a workflow and business process management platform founded around 2015 by Amit Kothari and headquartered in St. Louis, Missouri. It helps teams convert manual standard operating procedures, checklists, and repeatable processes into trackable, automated workflows without requiring coding or complex business process modeling notation. Tallyfy targets operations, HR, customer onboarding, and compliance teams at small and mid-size businesses that need to standardize recurring processes such as employee onboarding, client intake, or approval chains. The platform includes template-based workflow design, task tracking with reminders and watchers, approval steps, guest access for external participants without requiring them to have an account, single sign-on, and an AI assistant (Tallyfy AI) that helps draft and refine process templates. The company has stated it is profitable and independent, having raised a modest amount of funding (reported around $1.6 to 3.5 million) from non-VC investors including Republic and accelerators, and operates as a fully remote global team with no stated exit strategy. Pricing is seat-based: a Full Seat costs $25 per month billed annually ($30 month-to-month) and includes template creation, workflow launching, and task management, while a Light Seat costs $8.33 per month billed annually ($10 month-to-month) for users who only need to participate in and complete assigned tasks. All plans include free SSO, unlimited guest access, and a 14-day trial.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '117a7e22-499f-462f-92ab-79295cfef946';

